import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    const maxHeap = new MaxPriorityQueue({ priority: (x) => x.minCost });
    maxHeap.enqueue({ node: 0, totalCost: 0, minCost: Infinity });

    let result = -1;

    while (!maxHeap.isEmpty()) {
        const { element: { node, totalCost, minCost } } = maxHeap.dequeue();
        if (node === n - 1) {
            if (totalCost <= k) {
                result = Math.max(result, minCost === Infinity ? -1 : minCost);
            }
            continue;
        }

        for (const [neighbor, cost] of adj[node]) {
            if (!online[neighbor] && neighbor !== n - 1) {
                continue;
            }
            const newTotalCost = totalCost + cost;
            if (newTotalCost > k) {
                continue;
            }
            const newMinCost = Math.min(minCost, cost);
            maxHeap.enqueue({
                node: neighbor,
                totalCost: newTotalCost,
                minCost: newMinCost
            });
        }
    }

    return result;
}

class MaxPriorityQueue {
    constructor({ priority }) {
        this.priority = priority;
        this.queue = new MinPriorityQueue({ priority: (x) => -this.priority(x) });
    }

    enqueue(element) {
        this.queue.enqueue(element);
    }

    dequeue() {
        return this.queue.dequeue();
    }

    isEmpty() {
        return this.queue.isEmpty();
    }
}

