import heapq

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    for u, v, cost in edges:
        adj[u].append((v, cost))

    # Max heap based on minCost, stored as negative for min-heap simulation
    heap = []
    # Elements are (-minCost, totalCost, node)
    heapq.heappush(heap, (-float('inf'), 0, 0))

    result = -1

    while heap:
        neg_min_cost, total_cost, node = heapq.heappop(heap)
        current_min_cost = -neg_min_cost

        if node == n - 1:
            if total_cost <= k:
                if current_min_cost == float('inf'):
                    result = max(result, -1)
                else:
                    result = max(result, current_min_cost)
            continue

        for neighbor, cost in adj[node]:
            if not online[neighbor] and neighbor != n - 1:
                continue
            new_total_cost = total_cost + cost
            if new_total_cost > k:
                continue
            new_min_cost = min(current_min_cost, cost)
            heapq.heappush(heap, (-new_min_cost, new_total_cost, neighbor))

    return result
